diff --git a/src/Monolog/Formatter/JsonFormatter.php b/src/Monolog/Formatter/JsonFormatter.php
index fa11d0e..f6ad2cf 100644
--- a/src/Monolog/Formatter/JsonFormatter.php
+++ b/src/Monolog/Formatter/JsonFormatter.php
@@ -76,7 +76,18 @@ class JsonFormatter extends NormalizerFormatter
     {
         $normalized = $this->normalizeRecord($record);

-        return $this->toJson($normalized, true) . ($this->appendNewline ? "\n" : '');
+        $json = $this->toJson($normalized, true);
+        if (json_last_error() !== JSON_ERROR_NONE) {
+            $errorCode = json_last_error();
+            $errorMsg = json_last_error_msg();
+            $json = $this->toJson([
+                'message' => 'Failed to json_encode log record: ' . $errorMsg,
+                'error_code' => $errorCode,
+                'record_message' => mb_convert_encoding((string) $record->message, 'UTF-8', 'UTF-8'),
+            ], false);
+        }
+
+        return $json . ($this->appendNewline ? "\n" : '');
     }
